'use client';

import { useRouter } from 'next/navigation';
import { AdminNav } from '@/components/AdminNav';
import { clearSession, getSession } from '@/lib/auth';

export function AdminShell({
  title,
  subtitle,
  actions,
  children,
}: {
  title: string;
  subtitle?: string;
  actions?: React.ReactNode;
  children: React.ReactNode;
}) {
  const router = useRouter();
  const session = getSession();

  return (
    <div className="shell">
      <aside className="sidebar">
        <div className="brand">
          <div className="brand-mark">CX</div>
          <div>
            <div className="brand-title">Cafe-X Admin</div>
            <div className="brand-sub">Ops Console</div>
          </div>
        </div>
        <AdminNav />
        <div className="sidebar-meta">
          <div className="meta-row">
            <span className="meta-label">User</span>
            <span className="meta-value">{session?.username || '-'}</span>
          </div>
          <div className="meta-row">
            <span className="meta-label">Role</span>
            <span className="meta-value">{session?.role || '-'}</span>
          </div>
          <button
            className="btn outline full"
            onClick={() => {
              clearSession();
              router.push('/login');
            }}
          >
            Logout
          </button>
        </div>
      </aside>
      <section className="content">
        <header className="appbar">
          <div>
            <div className="title">{title}</div>
            {subtitle ? <div className="subtitle">{subtitle}</div> : null}
          </div>
          <div className="appbar-actions">
            {actions}
            <div className="pill success">API: 9000</div>
          </div>
        </header>
        <div className="content-inner">{children}</div>
      </section>
    </div>
  );
}
